using System.ComponentModel.DataAnnotations;

namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }

    [Required, StringLength(100)]
    public string Title { get; set; } = string.Empty;

    public string Category { get; set; } = string.Empty;

    [Required]
    public string Ingredients { get; set; } = string.Empty;

    [Required]
    public string Steps { get; set; } = string.Empty;

    public int RatingTotal { get; set; }
    public int RatingCount { get; set; }
    public double AverageRating => RatingCount > 0 ? (double)RatingTotal / RatingCount : 0;
}

public static class RecipeStore
{
    private static int _nextId = 4;

    public static List<Recipe> Recipes { get; } = new()
    {
        new Recipe { Id = 1, Title = "Classic Pancakes", Category = "Breakfast", Ingredients = "2 cups flour\n2 eggs\n1 cup milk\n2 tbsp sugar\n1 tsp baking powder", Steps = "1. Mix dry ingredients\n2. Whisk eggs and milk\n3. Combine wet and dry\n4. Cook on griddle until golden" },
        new Recipe { Id = 2, Title = "Caesar Salad", Category = "Lunch", Ingredients = "1 head romaine lettuce\n1/2 cup croutons\n1/4 cup parmesan\nCaesar dressing", Steps = "1. Chop lettuce\n2. Toss with dressing\n3. Top with croutons and parmesan" },
        new Recipe { Id = 3, Title = "Spaghetti Bolognese", Category = "Dinner", Ingredients = "400g spaghetti\n500g ground beef\n1 can crushed tomatoes\n1 onion\n2 cloves garlic\nOlive oil\nSalt and pepper", Steps = "1. Cook pasta al dente\n2. Sauté onion and garlic\n3. Brown ground beef\n4. Add tomatoes and simmer 20 min\n5. Serve sauce over pasta" },
    };

    public static List<string> Categories => Recipes.Select(r => r.Category).Distinct().ToList();

    public static void Add(Recipe recipe)
    {
        recipe.Id = _nextId++;
        Recipes.Add(recipe);
    }

    public static void AddRating(int recipeId, int stars)
    {
        var recipe = Recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.RatingTotal += stars;
            recipe.RatingCount++;
        }
    }
}

