@page "/recipes/{Category}"
@using RecipeShare.Models

<PageTitle>@Category Recipes - RecipeShare</PageTitle>

<h1>@Category Recipes</h1>
<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@Category</li>
    </ol>
</nav>

@if (recipes.Any())
{
    <div class="list-group mt-3">
        @foreach (var recipe in recipes)
        {
            <a href="/recipe/@recipe.Id" class="list-group-item list-group-item-action">
                <div class="d-flex justify-content-between align-items-center">
                    <h5 class="mb-1">@recipe.Title</h5>
                    @if (recipe.RatingCount > 0)
                    {
                        <span class="badge bg-warning text-dark">★ @recipe.AverageRating.ToString("0.0")</span>
                    }
                </div>
            </a>
        }
    </div>
}
else
{
    <p class="text-muted mt-3">No recipes in this category yet.</p>
}

@code {
    [Parameter] public string Category { get; set; } = string.Empty;
    private List<Recipe> recipes = new();

    protected override void OnParametersSet()
    {
        recipes = RecipeStore.Recipes
            .Where(r => r.Category.Equals(Category, StringComparison.OrdinalIgnoreCase))
            .ToList();
        Category = RecipeStore.Categories
            .FirstOrDefault(c => c.Equals(Category, StringComparison.OrdinalIgnoreCase)) ?? Category;
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Models

<PageTitle>@recipe?.Title - RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (recipe is not null)
        {
            <li class="breadcrumb-item"><a href="/recipes/@recipe.Category.ToLower()">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        }
    </ol>
</nav>

@if (recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
}
else
{
    <h1>@recipe.Title</h1>

    <div class="row mt-4">
        <div class="col-md-5">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">Ingredients</h5></div>
                <div class="card-body">
                    @foreach (var line in recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <p class="mb-1">• @line</p>
                    }
                </div>
            </div>
        </div>
        <div class="col-md-7">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">Steps</h5></div>
                <div class="card-body">
                    @foreach (var line in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <p>@line</p>
                    }
                </div>
            </div>
        </div>
    </div>

    <div class="mt-4">
        <h4>Rate this Recipe</h4>
        <StarRating RecipeId="recipe.Id" />
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeStore.Recipes.FirstOrDefault(r => r.Id == Id);
    }
}

@rendermode InteractiveServer
@using RecipeShare.Models

<div class="d-inline-flex align-items-center gap-2">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="btn btn-link p-0 fs-4 text-decoration-none"
                @onclick="() => SubmitRating(star)"
                disabled="@hasRated"
                title="Rate @star star(s)">
            <span style="color: @(star <= displayRating ? "#ffc107" : "#ccc")">★</span>
        </button>
    }
    @if (hasRated)
    {
        <span class="text-success ms-2">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    private int displayRating;
    private bool hasRated;

    private void SubmitRating(int stars)
    {
        if (hasRated) return;
        RecipeStore.AddRating(RecipeId, stars);
        displayRating = stars;
        hasRated = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Models
@using System.ComponentModel.DataAnnotations

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Recipe Submitted!</h4>
        <p>Your recipe "<strong>@model.Title</strong>" has been added. <a href="/recipe/@submittedId">View it here</a>.</p>
    </div>
    <button class="btn btn-primary" @onclick="Reset">Submit Another</button>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="model.Title" class="form-control" />
            <ValidationMessage For="() => model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="model.Category" class="form-select">
                <option value="">-- Select a category --</option>
                <option value="Breakfast">Breakfast</option>
                <option value="Lunch">Lunch</option>
                <option value="Dinner">Dinner</option>
                <option value="Dessert">Dessert</option>
                <option value="Snack">Snack</option>
            </InputSelect>
            <ValidationMessage For="() => model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="model.Ingredients" class="form-control" rows="5" />
            <ValidationMessage For="() => model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="model.Steps" class="form-control" rows="5" />
            <ValidationMessage For="() => model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
